import{_ as a,o as t,c as i,ae as n}from"./chunks/framework.EHGTsUvI.js";const m=JSON.parse('{"title":"Agile Vibe Coding Manifesto","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"README.md"}'),r={name:"index.md"};function o(s,e,l,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="agile-vibe-coding-manifesto" tabindex="-1">Agile Vibe Coding Manifesto <a class="header-anchor" href="#agile-vibe-coding-manifesto" aria-label="Permalink to &quot;Agile Vibe Coding Manifesto&quot;">​</a></h1><h2 id="preamble" tabindex="-1">Preamble <a class="header-anchor" href="#preamble" aria-label="Permalink to &quot;Preamble&quot;">​</a></h2><p>Software development increasingly involves collaboration between humans and automated systems capable of generating, modifying, and evolving code.</p><p>This shift dramatically increases the <strong>speed and scale of software creation</strong>. While this creates new opportunities, it also introduces new responsibilities for how software systems are designed, understood, and maintained.</p><p>Automation can accelerate development.</p><p><strong>Responsibility for the systems we build remains human.</strong></p><h2 id="relationship-to-the-agile-manifesto" tabindex="-1">Relationship to the Agile Manifesto <a class="header-anchor" href="#relationship-to-the-agile-manifesto" aria-label="Permalink to &quot;Relationship to the Agile Manifesto&quot;">​</a></h2><p>The <strong>Agile Manifesto and its twelve principles remain foundational</strong>.<br> They continue to guide how teams deliver value, collaborate, and continuously improve.</p><p>The Agile Vibe Coding Manifesto does not replace Agile.<br> It <strong>builds on top of it</strong>, extending its philosophy to environments where automated systems participate in the production and evolution of software.</p><h2 id="values" tabindex="-1">Values <a class="header-anchor" href="#values" aria-label="Permalink to &quot;Values&quot;">​</a></h2><p>We are discovering better ways of building software through collaboration between <strong>humans and automated systems</strong>.</p><p>Through this work we have come to value:</p><ul><li><strong>Accountability over anonymous generation</strong></li><li><strong>Traceable intent over opaque implementation</strong></li><li><strong>Discoverable domain structure over scattered code</strong></li><li><strong>Human-readable documentation over implicit knowledge</strong></li></ul><p>In the spirit of the original Agile Manifesto:</p><blockquote><p>&quot;While there is value in the items on the right, we value the items on the left more.&quot;<br> — Agile Manifesto (2001)</p></blockquote><h2 id="principles-of-agile-vibe-coding" tabindex="-1">Principles of Agile Vibe Coding <a class="header-anchor" href="#principles-of-agile-vibe-coding" aria-label="Permalink to &quot;Principles of Agile Vibe Coding&quot;">​</a></h2><p>These principles complement the original Agile principles and address the realities of software development where automated systems participate in producing code.</p><h3 id="_1-customer-value-remains-the-primary-objective" tabindex="-1">1. Customer value remains the primary objective <a class="header-anchor" href="#_1-customer-value-remains-the-primary-objective" aria-label="Permalink to &quot;1. Customer value remains the primary objective&quot;">​</a></h3><p>Acceleration in development must translate into validated customer value.<br> Speed without value is waste.</p><h3 id="_2-humans-remain-accountable-for-software-systems" tabindex="-1">2. Humans remain accountable for software systems <a class="header-anchor" href="#_2-humans-remain-accountable-for-software-systems" aria-label="Permalink to &quot;2. Humans remain accountable for software systems&quot;">​</a></h3><p>Regardless of how code is produced, software systems must have clear human responsibility.<br> Humans remain accountable for the systems that are deployed and operated.</p><h3 id="_3-every-change-has-traceable-intent" tabindex="-1">3. Every change has traceable intent <a class="header-anchor" href="#_3-every-change-has-traceable-intent" aria-label="Permalink to &quot;3. Every change has traceable intent&quot;">​</a></h3><p>Features, modifications, and generated code must be traceable to a requirement, decision, or problem being solved.</p><h3 id="_4-systems-remain-deterministic-and-verifiable" tabindex="-1">4. Systems remain deterministic and verifiable <a class="header-anchor" href="#_4-systems-remain-deterministic-and-verifiable" aria-label="Permalink to &quot;4. Systems remain deterministic and verifiable&quot;">​</a></h3><p>Software behaves predictably and is verified through tests.</p><h3 id="_5-documentation-preserves-shared-understanding" tabindex="-1">5. Documentation preserves shared understanding <a class="header-anchor" href="#_5-documentation-preserves-shared-understanding" aria-label="Permalink to &quot;5. Documentation preserves shared understanding&quot;">​</a></h3><p>Clear, human-readable documentation preserves the intent and structure of the system.</p><h3 id="_6-code-structure-reflects-the-domain" tabindex="-1">6. Code structure reflects the domain <a class="header-anchor" href="#_6-code-structure-reflects-the-domain" aria-label="Permalink to &quot;6. Code structure reflects the domain&quot;">​</a></h3><p>Software is organized around domain concepts rather than technical convenience.</p><h3 id="_7-architecture-guides-and-constrains-generation" tabindex="-1">7. Architecture guides and constrains generation <a class="header-anchor" href="#_7-architecture-guides-and-constrains-generation" aria-label="Permalink to &quot;7. Architecture guides and constrains generation&quot;">​</a></h3><p>Clear architectural boundaries and patterns guide automated generation.</p><h3 id="_8-automation-must-remain-verifiable" tabindex="-1">8. Automation must remain verifiable <a class="header-anchor" href="#_8-automation-must-remain-verifiable" aria-label="Permalink to &quot;8. Automation must remain verifiable&quot;">​</a></h3><p>Automated systems may generate, modify, or design software components.<br> Their outputs remain understandable, reviewable, and verifiable by humans.</p><h3 id="_9-generated-systems-remain-understandable-and-maintainable" tabindex="-1">9. Generated systems remain understandable and maintainable <a class="header-anchor" href="#_9-generated-systems-remain-understandable-and-maintainable" aria-label="Permalink to &quot;9. Generated systems remain understandable and maintainable&quot;">​</a></h3><p>Software remains readable, maintainable, and evolvable by humans, regardless of how it was produced.</p><h3 id="_10-context-is-explicit-and-versioned" tabindex="-1">10. Context is explicit and versioned <a class="header-anchor" href="#_10-context-is-explicit-and-versioned" aria-label="Permalink to &quot;10. Context is explicit and versioned&quot;">​</a></h3><p>Requirements, architecture, prompts, and domain language must be externalized, versioned, and shared.</p><h3 id="_11-knowledge-remains-accessible" tabindex="-1">11. Knowledge remains accessible <a class="header-anchor" href="#_11-knowledge-remains-accessible" aria-label="Permalink to &quot;11. Knowledge remains accessible&quot;">​</a></h3><p>Critical system knowledge lives in shared artifacts such as documentation, tests, and architectural records.</p><h3 id="_12-teams-regularly-reflect-on-the-use-of-automation" tabindex="-1">12. Teams regularly reflect on the use of automation <a class="header-anchor" href="#_12-teams-regularly-reflect-on-the-use-of-automation" aria-label="Permalink to &quot;12. Teams regularly reflect on the use of automation&quot;">​</a></h3><p>Teams regularly evaluate how automated systems are used in development and adjust practices accordingly.</p><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h2><p>This manifesto is a living document.</p><p>Proposed changes and discussions are maintained on GitHub:</p><p><a href="https://github.com/NachoColl/agilevibecodingmanifesto/" target="_blank" rel="noreferrer">https://github.com/NachoColl/agilevibecodingmanifesto/</a></p><h2 id="contributors" tabindex="-1">Contributors <a class="header-anchor" href="#contributors" aria-label="Permalink to &quot;Contributors&quot;">​</a></h2><p>This manifesto is the result of collaboration.</p><ul><li>Nacho Coll - <a href="https://github.com/NachoColl" target="_blank" rel="noreferrer">Github</a>, <a href="https://www.linkedin.com/in/nacho-coll/" target="_blank" rel="noreferrer">LinkedIn</a></li><li>Marek Kubis - <a href="https://www.linkedin.com/in/marek-kubis-236ab211/" target="_blank" rel="noreferrer">LinkedIn</a></li></ul><p><small>Additional contributors will be listed here as they participate in the evolution of the manifesto.</small></p>',49)])])}const b=a(r,[["render",o]]);export{m as __pageData,b as default};
